proof_block:
// Bridge the simple domain ensures via extensional equality so any
// det-check that compares dom()s lines up directly between the two runs.
assert(post1_self_.container_dom() =~= pre_self_.container_dom());
assert(post2_self_.container_dom() =~= pre_self_.container_dom());
assert(post1_self_.container_dom() =~= post2_self_.container_dom());

assert(post1_self_.proc_dom() =~= pre_self_.proc_dom().remove(proc_ptr));
assert(post2_self_.proc_dom() =~= pre_self_.proc_dom().remove(proc_ptr));
assert(post1_self_.proc_dom() =~= post2_self_.proc_dom());

assert(post1_self_.thread_dom() =~= pre_self_.thread_dom());
assert(post2_self_.thread_dom() =~= pre_self_.thread_dom());
assert(post1_self_.thread_dom() =~= post2_self_.thread_dom());

// Re-state the per-process `children` ensures with explicit triggers on
// the get_proc accessor so each run's quantifier instantiation pattern
// is fully pinned for z3 (the auto-chosen triggers in the ensures were
// ambiguous between the two runs).
assert(forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_ptr)]
    post1_self_.proc_dom().contains(p_ptr) ==>
    post1_self_.get_proc(p_ptr).children == pre_self_.get_proc(p_ptr).children);
assert(forall|p_ptr: ProcPtr|
    #![trigger post2_self_.get_proc(p_ptr)]
    post2_self_.proc_dom().contains(p_ptr) ==>
    post2_self_.get_proc(p_ptr).children == pre_self_.get_proc(p_ptr).children);

// Same lift for the `uppertree_seq` ensures, again with explicit
// per-run triggers on get_proc.
assert(forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_ptr)]
    post1_self_.proc_dom().contains(p_ptr) ==>
    post1_self_.get_proc(p_ptr).uppertree_seq == pre_self_.get_proc(p_ptr).uppertree_seq);
assert(forall|p_ptr: ProcPtr|
    #![trigger post2_self_.get_proc(p_ptr)]
    post2_self_.proc_dom().contains(p_ptr) ==>
    post2_self_.get_proc(p_ptr).uppertree_seq == pre_self_.get_proc(p_ptr).uppertree_seq);

// Same lift for the `subtree_set` ensures — the original ensures uses
// `#![trigger self.get_proc(p_p_ptr)]`, mirror it on both runs.
assert(forall|p_p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_p_ptr)]
    pre_self_.get_proc(proc_ptr).uppertree_seq@.contains(p_p_ptr) ==>
    post1_self_.get_proc(p_p_ptr).subtree_set@ =~=
        pre_self_.get_proc(p_p_ptr).subtree_set@.remove(proc_ptr));
assert(forall|p_p_ptr: ProcPtr|
    #![trigger post2_self_.get_proc(p_p_ptr)]
    pre_self_.get_proc(proc_ptr).uppertree_seq@.contains(p_p_ptr) ==>
    post2_self_.get_proc(p_p_ptr).subtree_set@ =~=
        pre_self_.get_proc(p_p_ptr).subtree_set@.remove(proc_ptr));

// Re-state the un-quantified wf / *_unchanged ensures so they exist as
// fresh proof-context facts for each run.
assert(post1_self_.wf());
assert(post2_self_.wf());
assert(containers_tree_unchanged(pre_self_, post1_self_));
assert(containers_tree_unchanged(pre_self_, post2_self_));
assert(processes_fields_unchanged(pre_self_, post1_self_));
assert(processes_fields_unchanged(pre_self_, post2_self_));
assert(threads_unchanged(pre_self_, post1_self_));
assert(threads_unchanged(pre_self_, post2_self_));

// Bridge pointwise: for each surviving process, both runs equal pre, so
// they equal each other. Use an explicit dual-trigger (one mention of
// each run's get_proc) so the new quantifier is unambiguously
// instantiable for the determinism check that follows.
assert forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_ptr), post2_self_.get_proc(p_ptr)]
    post1_self_.proc_dom().contains(p_ptr) implies
        post1_self_.get_proc(p_ptr).children == post2_self_.get_proc(p_ptr).children
        && post1_self_.get_proc(p_ptr).uppertree_seq == post2_self_.get_proc(p_ptr).uppertree_seq
    by {
    assert(post2_self_.proc_dom().contains(p_ptr));
    assert(post1_self_.get_proc(p_ptr).children == pre_self_.get_proc(p_ptr).children);
    assert(post2_self_.get_proc(p_ptr).children == pre_self_.get_proc(p_ptr).children);
    assert(post1_self_.get_proc(p_ptr).uppertree_seq == pre_self_.get_proc(p_ptr).uppertree_seq);
    assert(post2_self_.get_proc(p_ptr).uppertree_seq == pre_self_.get_proc(p_ptr).uppertree_seq);
}

// Bridge the `subtree_set` ensures pointwise on the uppertree_seq of the
// removed proc. Both runs' subtree_set equal pre.subtree_set.remove(proc_ptr)
// (as Set, via =~=), so they =~= each other; explicit dual-trigger.
assert forall|p_p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_p_ptr), post2_self_.get_proc(p_p_ptr)]
    pre_self_.get_proc(proc_ptr).uppertree_seq@.contains(p_p_ptr) implies
        post1_self_.get_proc(p_p_ptr).subtree_set@ =~=
            post2_self_.get_proc(p_p_ptr).subtree_set@
    by {
    assert(post1_self_.get_proc(p_p_ptr).subtree_set@ =~=
        pre_self_.get_proc(p_p_ptr).subtree_set@.remove(proc_ptr));
    assert(post2_self_.get_proc(p_p_ptr).subtree_set@ =~=
        pre_self_.get_proc(p_p_ptr).subtree_set@.remove(proc_ptr));
}
